import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="lg" 
      style={{ 
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' 
      }}
    >
      <Stack gap={24}>
        {/* Main Weather Display */}
        <Stack align="center" gap={4}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text 
            variant="label" 
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            {temperature}°{unit}
          </Heading>
        </Stack>

        {/* Stats Row */}
        <Stack direction="horizontal" justify="between">
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={12}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8} style={{ flex: 1 }}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {item.day ?? '—'}
              </Text>
              <Text size="lg">{item.icon ?? '☁️'}</Text>
              <Stack gap={2} align="center">
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? 0}°
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low ?? 0}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Divider,
} from '@ggui-ai/design/primitives';
import { Modal } from '@ggui-ai/design/components';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-info-200)',
  'nonmetal': 'var(--ggui-color-success-100)',
  'alkali-metal': 'var(--ggui-color-warning-100)',
  'halogen': 'var(--ggui-color-error-100)',
  'default': 'var(--ggui-color-neutral-100)',
};

export default function GeneratedComponent(props: Props) {
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = props.elements.filter(
    (e) =>
      (e.name?.toLowerCase() ?? '').includes(query.toLowerCase()) ||
      (e.symbol?.toLowerCase() ?? '').includes(query.toLowerCase())
  );

  const getCategoryColor = (cat?: string) =>
    CATEGORY_COLORS[cat || 'default'] ?? CATEGORY_COLORS.default;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Input
          label="Search element by name or symbol"
          value={query}
          onChange={setQuery}
          placeholder="e.g. Hydrogen or H"
        />

        <div
          role="grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            width: '100%',
          }}
        >
          {filtered.map((el) => (
            <div
              key={el.atomicNumber}
              role="gridcell"
              tabIndex={0}
              aria-label={`${el.atomicNumber}: ${el.name} (${el.symbol})`}
              onClick={() => setSelected(el)}
              onKeyDown={(e) => e.key === 'Enter' && setSelected(el)}
              style={{
                gridColumn: el.col,
                gridRow: el.row,
                cursor: 'pointer',
              }}
            >
              <Card
                radius="sm"
                padding="var(--ggui-spacing-2, 8px)"
                border={true}
                style={{
                  backgroundColor: getCategoryColor(el.category),
                  transition: 'background-color 200ms ease',
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  minHeight: '60px',
                }}
              >
                <Text size="xs">{el.atomicNumber}</Text>
                <Box style={{ textAlign: 'center' }}>
                  <Heading level={4}>{el.symbol}</Heading>
                </Box>
              </Card>
            </div>
          ))}
        </div>

        <Divider />

        <Stack direction="horizontal" justify="center" gap="var(--ggui-spacing-4, 16px)" wrap>
          {Object.keys(CATEGORY_COLORS).map(
            (cat) =>
              cat !== 'default' && (
                <Stack
                  key={cat}
                  direction="horizontal"
                  align="center"
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  <Box
                    style={{
                      width: 12,
                      height: 12,
                      backgroundColor: CATEGORY_COLORS[cat],
                    }}
                  />
                  <Text variant="caption">{cat.replace('-', ' ')}</Text>
                </Stack>
              )
          )}
        </Stack>
      </Stack>

      <Modal open={!!selected} onClose={() => setSelected(null)} title={selected?.name ?? ''}>
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Text variant="body">Symbol: {selected?.symbol}</Text>
          <Text variant="body">Atomic Number: {selected?.atomicNumber}</Text>
          <Text variant="body">Atomic Weight: {selected?.atomicWeight}</Text>
          <Text variant="body">Category: {selected?.category}</Text>
        </Stack>
      </Modal>
    </Container>
  );
}

import React from 'react';
import { Container, Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const unit = props.unit ?? '';
  const unitSuffix = unit.trim().length > 0 ? ` ${unit}` : '';

  const conditionIcon = props.forecast?.[0]?.icon ?? '';

  const formatTempsLine = (item: { high?: number; low?: number }) => {
    const hasHigh = typeof item.high === 'number';
    const hasLow = typeof item.low === 'number';
    if (!hasHigh && !hasLow) return '';

    const highPart = hasHigh ? `High ${item.high}` : '';
    const lowPart = hasLow ? `Low ${item.low}` : '';

    if (hasHigh && hasLow) return `${highPart}${unitSuffix} / ${lowPart}${unitSuffix}`;
    if (hasHigh) return `${highPart}${unitSuffix}`;
    return `${lowPart}${unitSuffix}`;
  };

  return (
    <Container maxWidth="sm" padding={0}>
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-6, 24px)">
        <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)">
          <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)">
            <Stack direction="horizontal" align="center" justify="between" gap="var(--ggui-spacing-4, 16px)">
              <Heading level={4}>{props.city}</Heading>
            </Stack>

            <Heading level={2}>
              {props.temperature}
              {unitSuffix}
            </Heading>

            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              {conditionIcon ? (
                <Text as="span" variant="bodyLarge" aria-label="Current condition icon">
                  {conditionIcon}
                </Text>
              ) : null}
              <Text variant="label" truncate>
                {props.condition}
              </Text>
            </Stack>
          </Stack>

          <Divider />

          <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="stretch" wrap={true}>
            <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)" style={{ minWidth: 0 }}>
              <Text variant="overline">Humidity</Text>
              <Text variant="bodyLarge" aria-label="Humidity">
                {props.humidity}%
              </Text>
            </Stack>

            <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)" style={{ minWidth: 0 }}>
              <Text variant="overline">Wind</Text>
              <Text variant="bodyLarge" aria-label="Wind speed">
                {props.windSpeed}
              </Text>
            </Stack>
          </Stack>

          <Divider margin="var(--ggui-spacing-4, 16px)" />

          <Stack
            direction="horizontal"
            gap="var(--ggui-spacing-2, 8px)"
            justify="between"
            wrap={true}
            aria-label="5-day forecast"
          >
            {props.forecast.map((item, index) => {
              const day = item.day;
              const icon = item.icon;
              const high = item.high;
              const low = item.low;

              const hasAnyTemp = typeof high === 'number' || typeof low === 'number';
              const tempsLine = hasAnyTemp ? formatTempsLine({ high, low }) : '';

              return (
                <Stack
                  key={`${day ?? 'day'}-${icon ?? 'icon'}-${index}`}
                  direction="vertical"
                  align="center"
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  {typeof day === 'string' && day ? (
                    <Text variant="caption" truncate>
                      {day}
                    </Text>
                  ) : null}

                  {typeof icon === 'string' && icon ? (
                    <Text as="span" variant="bodyLarge" aria-label="Forecast icon">
                      {icon}
                    </Text>
                  ) : null}

                  {tempsLine ? (
                    <Text variant="bodySmall" aria-label="High and low temperatures">
                      {tempsLine}
                    </Text>
                  ) : null}
                </Stack>
              );
            })}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
